import java.io.IOException;
import java.io.PrintWriter;

import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSecureServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Encode the user input to prevent XSS attacks
        Encoder encoder = ESAPI.encoder();
        String encodedInput = encoder.encodeForHTML(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>XSS Secure Page</title></head>");
        out.println("<body>");

        // Output sanitized user input
        out.println("<p>User Input: " + encodedInput + "</p>");

        out.println("</body>");
        out.println("</html>");

